declare var Chart: any;

@Component({
  selector: 'app-crop-guide',
  templateUrl: './crop-guide.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule]
})
export class CropGuideComponent implements AfterViewInit, OnDestroy {
  @ViewChild('cropNutrientChart') chartCanvas!: ElementRef<HTMLCanvasElement>;

  generateFertilizerForCrop = output<Deficiency[]>();

  private dataService = inject(DataService);
  private chart: any;

  cropsData = this.dataService.getData().crops;
  cropNames = Object.keys(this.cropsData);
  selectedCropName = signal(this.cropNames[0]);

  ngAfterViewInit(): void {
    this.createChart();
  }

  ngOnDestroy(): void {
    this.chart?.destroy();
  }

  selectCrop(event: Event): void {
    const cropName = (event.target as HTMLSelectElement).value;
    this.selectedCropName.set(cropName);
    this.createChart();
  }

  createChart(): void {
    if (!this.chartCanvas) return;

    const crop = this.cropsData[this.selectedCropName()];
    const chartData = {
      labels: Object.keys(crop.needs),
      datasets: [{
        label: 'Relative Requirement',
        data: Object.values(crop.needs),
        backgroundColor: ['#A47E3B', '#C8A572', '#E5D3B3'],
        borderColor: '#FDFBF5',
        borderWidth: 2,
        borderRadius: 5
      }]
    };

    if (this.chart) {
      this.chart.destroy();
    }

    this.chart = new Chart(this.chartCanvas.nativeElement, {
      type: 'bar',
      data: chartData,
      options: {
        indexAxis: 'y',
        responsive: true,
        maintainAspectRatio: false,
        plugins: { legend: { display: false } },
        scales: {
          x: { grid: { display: false }, ticks: { display: false, max: 3, min: 0 } },
          y: { grid: { display: false }, ticks: { color: '#4F4A45', font: { size: 14 } } }
        }
      }
    });
  }

  onGenerateFertilizer(): void {
    const crop = this.cropsData[this.selectedCropName()];
    const needs = crop.needs as { [key: string]: number };
    const deficiencies: Deficiency[] = [];
    const levelMap: { [key: number]: string } = {
      1: 'Low Need',
      2: 'Medium Need',
      3: 'High Need'
    };

    for (const key in needs) {
        const nutrientMatch = key.match(/\((N|P|K)\)/);
        if (nutrientMatch) {
            const nutrient = nutrientMatch[1] as 'N' | 'P' | 'K';
            const weight = needs[key];
            if (weight > 0) {
                deficiencies.push({
                    nutrient: nutrient,
                    level: levelMap[weight] || 'Custom Need',
                    weight: weight
                });
            }
        }
    }
    this.generateFertilizerForCrop.emit(deficiencies);
  }
}

export interface Deficiency {
  nutrient: 'N' | 'P' | 'K';
  level: string;
  weight: number;
}

import { Injectable } from '@angular/core';
import { AnalysisResult } from './gemini.service';

export interface GalleryItem {
  id: number;
  date: string;
  imageBase64: string;
  analysisResult: AnalysisResult;
  thumbnailBase64: string;
}

@Injectable({ providedIn: 'root' })
export class GalleryService {
  private readonly STORAGE_KEY = 'plant_analysis_gallery';

  getGalleryItems(): GalleryItem[] {
    const itemsJson = localStorage.getItem(this.STORAGE_KEY);
    return itemsJson ? JSON.parse(itemsJson) : [];
  }

  async addGalleryItem(imageBase64: string, analysisResult: AnalysisResult): Promise<void> {
    const thumbnailBase64 = await this.createThumbnail(imageBase64);
    const newItem: GalleryItem = {
      id: Date.now(),
      date: new Date().toISOString(),
      imageBase64,
      analysisResult,
      thumbnailBase64
    };
    const items = this.getGalleryItems();
    items.unshift(newItem); // Add to the beginning for chronological order
    localStorage.setItem(this.STORAGE_KEY, JSON.stringify(items));
  }

  deleteGalleryItem(id: number): void {
    let items = this.getGalleryItems();
    items = items.filter(item => item.id !== id);
    localStorage.setItem(this.STORAGE_KEY, JSON.stringify(items));
  }

  private createThumbnail(imageBase64: string, maxWidth = 150, maxHeight = 150): Promise<string> {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = `data:image/jpeg;base64,${imageBase64}`;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        if (width > height) {
          if (width > maxWidth) {
            height *= maxWidth / width;
            width = maxWidth;
          }
        } else {
          if (height > maxHeight) {
            width *= maxHeight / height;
            height = maxHeight;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg').split(',')[1]);
      };
      img.onerror = () => {
        // Fallback to original if something goes wrong
        resolve(imageBase64);
      };
    });
  }
}

import { Component, ChangeDetectionStrategy, input, output } from '@angular/core';
