// Shared serial logic for simplicity in this demo
async function connectSerial() {
    if (!('serial' in navigator)) {
        alert("Web Serial not supported.");
        return;
    }
    try {
        state.serialPort = await navigator.serial.requestPort();
        await state.serialPort.open({ baudRate: 9600 });

        // Start Reading
        readSerialLoop();
        updateConnectionStatus('connected');
    } catch (err) {
        console.error(err);
        updateConnectionStatus('error');
    }
}

async function readSerialLoop() {
    const textDecoder = new TextDecoderStream();
    const readableStreamClosed = state.serialPort.readable.pipeTo(textDecoder.writable);
    const reader = textDecoder.readable.getReader();
    state.serialReader = reader;

    try {
        while (true) {
            const { value, done } = await reader.read();
            if (done) break;
            if (value) parseSerialData(value);
        }
    } catch (err) {
        console.error(err);
    }
}

