function updateGeneratorUI() {
    const banner = document.getElementById('gen-source-banner');
    const inputArea = document.getElementById('gen-input-area');
    const diagArea = document.getElementById('gen-diagnosis-area');
    const recipeArea = document.getElementById('gen-recipe-area');
    const list = document.getElementById('gen-deficiency-list');
    const recipeOutput = document.getElementById('gen-recipe-output');

    // Reset
    list.innerHTML = '';
    recipeOutput.innerHTML = '';

    let deficiencies = [];

    // 1. Determine Source & Deficiencies
    if (state.genData) {
        banner.classList.remove('hidden');
        document.getElementById('gen-source-title').textContent = state.genData.source === 'crop' ? "Using Crop Guide Data" : "Using Plant Analyser Data";
        deficiencies = state.genData.deficiencies;
        inputArea.classList.add('hidden');
    } else {
        banner.classList.add('hidden');
        inputArea.classList.remove('hidden');
        // If simulated sensor reading was done, use that
        if (state.sensorDefs) deficiencies = state.sensorDefs;
    }

    // 2. Show Diagnosis
    if (deficiencies.length > 0) {
        diagArea.classList.remove('hidden');
        deficiencies.forEach(def => {
            const li = document.createElement('li');
            li.className = "flex items-start bg-[#F1EADF] p-3 rounded-lg";
            li.innerHTML = `
                <span class="text-2xl mr-3">${def.nutrient === 'N' ? '🌿' : def.nutrient === 'P' ? '🌸' : '🍓'}</span>
                <div>
                    <p class="font-bold text-[#6A5A4F]">${def.level} in ${def.nutrient}</p>
                    <p class="text-gray-600">Recommended: <span class="font-semibold">${DATA.organics.additives[def.nutrient]?.name || 'Unknown'}</span></p>
                </div>
            `;
            list.appendChild(li);
        });

        // 3. Calculate Recipe
        recipeArea.classList.remove('hidden');
        calculateRecipe(deficiencies);
    } else {
        diagArea.classList.add('hidden');
        recipeArea.classList.add('hidden');
    }
}

function calculateRecipe(deficiencies) {
    const qty = parseFloat(document.getElementById('gen-qty').value) || 10;
    const unit = document.getElementById('gen-unit').value;
    const out = document.getElementById('gen-recipe-output');
    out.innerHTML = '';

    const baseAmount = qty * 0.6;
    const additiveTotal = qty * 0.4;

    // Add Base
    const baseRow = document.createElement('div');
    baseRow.className = "flex justify-between py-3";
    baseRow.innerHTML = `<span class="text-gray-700">Cow Dung Base</span><span class="font-bold text-[#4F4A45]">${baseAmount.toFixed(2)} ${unit}</span>`;
    out.appendChild(baseRow);

    const totalWeight = deficiencies.reduce((sum, d) => sum + d.weight, 0);

    deficiencies.forEach(def => {
        const additive = DATA.organics.additives[def.nutrient];
        if (additive) {
            const amt = (def.weight / totalWeight) * additiveTotal;
            const row = document.createElement('div');
            row.className = "flex justify-between py-3";
            row.innerHTML = `<span class="text-gray-700">${additive.name}</span><span class="font-bold text-[#4F4A45]">${amt.toFixed(2)} ${unit}</span>`;
            out.appendChild(row);
        }
    });
}

