        <p class="mb-4 text-gray-700">${soil.characteristics}</p>
        <div class="mb-4">
            <h4 class="font-semibold text-lg mb-2">Nutrient Profile:</h4>
            <p class="text-gray-600">${soil.profileText}</p>
        </div>
        <div>
            <h4 class="font-semibold text-lg mb-2">Suitable Crops:</h4>
            <p class="text-gray-600">${soil.crops}</p>
        </div>
