    // Chart
    const ctx = document.getElementById('soil-chart').getContext('2d');
    if (soilChart) soilChart.destroy();
    soilChart = new Chart(ctx, {
        type: 'radar',
        data: {
            labels: Object.keys(soil.profile),
            datasets: [{
                label: 'Level',
                data: Object.values(soil.profile),
                backgroundColor: 'rgba(164, 126, 59, 0.2)',
