    result: null
};

function setPlantView(v) {
    plantState.view = v;
    ['idle', 'camera', 'preview', 'loading', 'result', 'gallery'].forEach(view => {
        const el = document.getElementById(`plant-view-${view}`);
        if(v === view) el.classList.remove('hidden');
        else el.classList.add('hidden');
