// Camera Logic
const videoEl = document.getElementById('camera-video');
const canvasEl = document.getElementById('camera-canvas');
let stream = null;

document.getElementById('btn-camera-start').onclick = async () => {
    try {
        stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
        videoEl.srcObject = stream;
        setPlantView('camera');
    } catch(e) { alert("Camera error: " + e.message); }
};

document.getElementById('btn-camera-cancel').onclick = () => {
    if(stream) stream.getTracks().forEach(t => t.stop());
    setPlantView('idle');
};

document.getElementById('btn-camera-capture').onclick = () => {
    canvasEl.width = videoEl.videoWidth;
    canvasEl.height = videoEl.videoHeight;
    canvasEl.getContext('2d').drawImage(videoEl, 0, 0);
    plantState.image = canvasEl.toDataURL('image/jpeg').split(',')[1];
    document.getElementById('image-preview').src = `data:image/jpeg;base64,${plantState.image}`;
    if(stream) stream.getTracks().forEach(t => t.stop());
    setPlantView('preview');
};

// Upload Logic
document.getElementById('btn-upload').onclick = () => document.getElementById('file-input').click();
document.getElementById('file-input').onchange = (e) => {
    const file = e.target.files[0];
    if(file) {
        const reader = new FileReader();
        reader.onload = (evt) => {
            plantState.image = evt.target.result.split(',')[1];
            document.getElementById('image-preview').src = evt.target.result;
            setPlantView('preview');
        };
        reader.readAsDataURL(file);
