function renderGallery() {
    const grid = document.getElementById('gallery-grid');
    grid.innerHTML = '';
    state.analysisHistory.forEach(item => {
        const div = document.createElement('div');
        div.className = "group relative border-2 border-transparent hover:border-[#A47E3B] rounded-lg overflow-hidden shadow-md cursor-pointer h-40";
        div.innerHTML = `
            <img src="data:image/jpeg;base64,${item.image}" class="w-full h-full object-cover">
            <div class="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-60 transition-opacity flex flex-col justify-between p-2">
                <button class="self-end text-white bg-red-600 rounded-full w-6 h-6 flex items-center justify-center opacity-0 group-hover:opacity-100" onclick="event.stopPropagation(); window.deleteGalleryItem(${item.id})">×</button>
                <div class="text-white opacity-0 group-hover:opacity-100">
                    <p class="font-bold text-xs truncate">${item.result.overallHealth.status}</p>
                    <p class="text-[10px]">${new Date(item.date).toLocaleDateString()}</p>
                </div>
            </div>
        `;
        div.onclick = () => {
            plantState.image = item.image;
            plantState.result = item.result;
            renderResult(item.result);
            setPlantView('result');
        };
        grid.appendChild(div);
    });
}

window.deleteGalleryItem = (id) => {
    state.analysisHistory = state.analysisHistory.filter(i => i.id !== id);
    localStorage.setItem('plant_analysis_gallery', JSON.stringify(state.analysisHistory));
    renderGallery();
    if(state.analysisHistory.length === 0) document.getElementById('gallery-trigger-container').classList.add('hidden');
};

