// Mock Interval for Tank Monitor when "Connected"
let tankInterval;
function updateConnectionStatus(status) {
    const tankStatus = document.getElementById('tank-status');
    const motorStatus = document.getElementById('motor-status');
    const tankBtn = document.getElementById('btn-tank-connect');
    const motorBtn = document.getElementById('btn-motor-connect');
    const motorToggle = document.getElementById('btn-motor-toggle');

    if (status === 'connected') {
        if(tankBtn) {
            tankBtn.textContent = "Disconnect";
            tankBtn.classList.replace('bg-green-600', 'bg-red-600');
            tankBtn.classList.replace('hover:bg-green-700', 'hover:bg-red-700');
        }

        if(motorBtn) {
            motorBtn.textContent = "Disconnect";
            motorBtn.classList.replace('bg-green-600', 'bg-red-600');
        }

        if(tankStatus) tankStatus.textContent = "Receiving real-time data.";
        if(motorStatus) motorStatus.textContent = "Device connected.";
        if(motorToggle) {
            motorToggle.disabled = false;
            motorToggle.classList.remove('cursor-not-allowed', 'opacity-50');
        }

        // Start Mock Data Stream
        if(tankInterval) clearInterval(tankInterval);
        tankInterval = setInterval(() => {
            const elTemp = document.getElementById('tank-temp');
            if(elTemp) elTemp.textContent = (25 + Math.random() * 5).toFixed(1);

            const elHum = document.getElementById('tank-hum');
            if(elHum) elHum.textContent = (60 + Math.random() * 10).toFixed(1);

            const elMoist = document.getElementById('tank-moist');
            if(elMoist) elMoist.textContent = (50 + Math.random() * 10).toFixed(1);

            const elPh = document.getElementById('tank-ph');
            if(elPh) elPh.textContent = (6.5 + Math.random()).toFixed(1);

            const elGas = document.getElementById('tank-gas');
            if(elGas) elGas.textContent = Math.floor(Math.random() * 10);
        }, 2000);

    } else {
        // Disconnected state
        if(tankInterval) clearInterval(tankInterval);
        ['tank-temp', 'tank-hum', 'tank-moist', 'tank-ph', 'tank-gas'].forEach(id => {
            const el = document.getElementById(id);
            if(el) el.textContent = '--';
        });

        if(tankBtn) {
            tankBtn.textContent = "Connect to Arduino";
            tankBtn.classList.replace('bg-red-600', 'bg-green-600');
            tankBtn.classList.replace('hover:bg-red-700', 'hover:bg-green-700');
        }

        if(motorBtn) {
            motorBtn.textContent = "Connect to Arduino";
            motorBtn.classList.replace('bg-red-600', 'bg-green-600');
        }

        if(tankStatus) tankStatus.textContent = "Connect to device.";
        if(motorStatus) motorStatus.textContent = "Connect to control motor.";

        if(motorToggle) {
            motorToggle.disabled = true;
            motorToggle.classList.add('cursor-not-allowed', 'opacity-50');
        }
        state.isMotorOn = false;
        updateMotorUI();
    }
}

