// GEMINI ANALYSIS
const btnAnalyze = document.getElementById('btn-analyze');
if(btnAnalyze) {
    btnAnalyze.onclick = async () => {
        if(!state.geminiApiKey) {
            alert("API Key missing. Cannot call Gemini API.");
            return;
        }
        setPlantView('loading');

        const ai = new GoogleGenAI({ apiKey: state.geminiApiKey });
        const prompt = `You are an expert agronomist specializing in South Indian agriculture. Analyze the provided image of a plant leaf/plant. Identify diseases, pest attacks, and nutrient deficiencies. Provide a detailed diagnosis and actionable, step-by-step recommendations for treatment and prevention. Focus on solutions relevant to the South Indian context. Structure your response according to the provided JSON schema.`;

        try {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: { parts: [{ text: prompt }, { inlineData: { mimeType: 'image/jpeg', data: plantState.image } }] },
                config: {
                    responseMimeType: 'application/json',
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            overallHealth: { type: Type.OBJECT, properties: { status: {type: Type.STRING}, summary: {type: Type.STRING} } },
                            detectedIssues: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: {type: Type.STRING}, type: {type: Type.STRING}, description: {type: Type.STRING} } } },
                            nutrientDeficiencies: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { nutrient: {type: Type.STRING}, symptoms: {type: Type.STRING} } } },
                            treatmentRecommendations: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { title: {type: Type.STRING}, steps: {type: Type.ARRAY, items: {type: Type.STRING}}, type: {type: Type.STRING} } } },
                            preventiveMeasures: { type: Type.ARRAY, items: { type: Type.STRING } }
                        }
                    }
                }
            });

            const result = JSON.parse(response.text());
            plantState.result = result;
            renderResult(result);
            saveToGallery(plantState.image, result);
            setPlantView('result');

        } catch (err) {
            alert("Analysis failed: " + err.message);
            setPlantView('preview');
        }
    };
}

function renderResult(data) {
    const resImg = document.getElementById('result-image');
    if(resImg) resImg.src = `data:image/jpeg;base64,${plantState.image}`;
    const content = document.getElementById('result-content');
    if(!content) return;

    // Check for NPK for Generator Button
    const hasNPK = data.nutrientDeficiencies?.some(d => ['nitrogen','phosphorus','potassium'].includes(d.nutrient.toLowerCase()));

    let html = `
        <div>
            <h3 class="text-xl font-bold text-[#6A5A4F] border-b-2 border-[#F1EADF] pb-2 mb-3">Health: <span class="text-[#A47E3B]">${data.overallHealth.status}</span></h3>
            <p class="text-gray-700">${data.overallHealth.summary}</p>
        </div>
    `;

    if(data.detectedIssues?.length) {
        html += `<div><h3 class="text-xl font-bold text-[#6A5A4F] mb-3">Issues</h3><div class="space-y-4">`;
        data.detectedIssues.forEach(i => {
            html += `<div class="p-3 bg-red-50 border border-red-200 rounded-lg"><p class="font-bold text-red-800">${i.name} (${i.type})</p><p class="text-red-700 text-sm">${i.description}</p></div>`;
        });
        html += `</div></div>`;
    }

    if(data.nutrientDeficiencies?.length) {
        html += `<div><h3 class="text-xl font-bold text-[#6A5A4F] mb-3">Deficiencies</h3><div class="space-y-4">`;
        data.nutrientDeficiencies.forEach(d => {
            html += `<div class="p-3 bg-yellow-50 border border-yellow-200 rounded-lg"><p class="font-bold text-yellow-800">${d.nutrient}</p><p class="text-yellow-700 text-sm">${d.symptoms}</p></div>`;
        });
        html += `</div>`;
        if(hasNPK) {
            html += `<button onclick="window.sendToGen()" class="mt-4 w-full bg-green-600 text-white font-bold py-3 px-6 rounded-full shadow-lg hover:bg-green-700">Generate Fertilizer Recipe</button>`;
        }
        html += `</div>`;
    }

    if(data.treatmentRecommendations?.length) {
        html += `<div><h3 class="text-xl font-bold text-[#6A5A4F] mb-3">Treatment</h3><div class="space-y-4">`;
        data.treatmentRecommendations.forEach(t => {
            html += `<div class="p-3 bg-blue-50 border border-blue-200 rounded-lg"><p class="font-bold text-blue-800">${t.title} (${t.type})</p><ul class="list-disc list-inside text-blue-700 text-sm mt-2">`;
            t.steps.forEach(s => html += `<li>${s}</li>`);
            html += `</ul></div>`;
        });
        html += `</div></div>`;
    }

    content.innerHTML = html;
}

window.sendToGen = () => {
    const defs = plantState.result.nutrientDeficiencies
        .map(d => {
            const n = d.nutrient.toLowerCase();
            const map = {'nitrogen':'N', 'phosphorus':'P', 'potassium':'K'};
            if(map[n]) return { nutrient: map[n], level: 'Deficient', weight: 1 };
            return null;
        })
        .filter(x => x);
    state.genData = { source: 'analyser', deficiencies: defs };
    showSection('section-generator');
    updateGeneratorUI();
};

