  // --- Web Serial API Methods ---
  async connect(): Promise<void> {
    if (!('serial' in navigator)) {
      this.connectionStatusSubject.next('error');
      console.error('Web Serial API not supported.');
      alert('Web Serial API is not supported in your browser.');
      return;
    }

    if (this.port) {
        console.log("A connection attempt is already in progress or established.");
        return;
    }

    try {
      this.connectionStatusSubject.next('connecting');
      this.port = await (navigator as any).serial.requestPort();
      await this.port.open({ baudRate: 9600 });

      const textEncoder = new TextEncoderStream();
      const writableStreamClosed = textEncoder.readable.pipeTo(this.port.writable);
      this.writer = textEncoder.writable.getWriter();

      this.connectionStatusSubject.next('connected');
      this.keepReading = true;
      this.readLoop();
    } catch (err) {
      console.error('There was an error opening the serial port:', err);
      this.connectionStatusSubject.next('error');
      this.port = undefined;
    }
  }

  async disconnect(): Promise<void> {
    if (!this.port) return;

    this.keepReading = false;

    if (this.writer) {
      try {
        await this.writer.close();
      } catch (error) {
        console.error("Error closing writer:", error);
      }
    }

    if (this.reader) {
        try {
            await this.reader.cancel();
        } catch(error) {
            console.error("Error cancelling reader:", error);
        }
    }
  }

  async sendCommand(command: string): Promise<void> {
    if (!this.writer) {
      console.error('Serial port not writable.');
      return;
    }
    try {
      await this.writer.write(command + '\n');
    } catch (error) {
      console.error('Error writing to serial port:', error);
    }
  }

  private async readLoop(): Promise<void> {
    const textDecoder = new TextDecoderStream();
    const readableStreamClosed = this.port.readable.pipeTo(textDecoder.writable);
    this.reader = textDecoder.readable.getReader();
    let partialData = '';

    while (this.port.readable && this.keepReading) {
      try {
        const { value, done } = await this.reader.read();
        if (done) {
          break;
        }

        partialData += value;
        let newlineIndex;
        while ((newlineIndex = partialData.indexOf('\n')) >= 0) {
            const jsonString = partialData.substring(0, newlineIndex).trim();
            partialData = partialData.substring(newlineIndex + 1);

            // Explicit check to prevent parsing "undefined" string
            if (jsonString && jsonString !== "undefined" && jsonString !== "null") {
                try {
                    const data = JSON.parse(jsonString);
                    // Check for complete sensor data packet from Arduino
                    if (data.temp !== undefined && data.hum !== undefined && data.gas !== undefined && data.moist !== undefined && data.relay !== undefined) {
                      this.tankDataSubject.next({
                        temp: data.temp,
                        humidity: data.hum,
                        methane: data.gas,
                        moisture: data.moist
                      });
                      this.relayStateSubject.next(data.relay === 'ON');
                    } else if (data.error) {
                      console.error('Error from Arduino:', data.error);
                    } else if (data.status) {
                      console.log('Status from Arduino:', data.status);
                    }
                } catch (e) {
                    console.warn('Could not parse JSON from serial port:', jsonString);
                }
            }
        }
      } catch (error) {
        console.error('Error reading from serial port:', error);
        this.keepReading = false;
      }
    }

    this.reader.releaseLock();
    await readableStreamClosed.catch(() => { /* Ignore cancellation error */ });

    try {
      await this.port.close();
    } catch(error) {
       console.error("Error closing port:", error);
    } finally {
       this.port = undefined;
       this.reader = undefined;
       this.writer = undefined;
       this.connectionStatusSubject.next('disconnected');
       this.relayStateSubject.next(false);
    }
  }

  // --- Mock Data Methods ---
  getNpkReadings(): Observable<NpkReadings> {
    const readings: NpkReadings = {
      n: this.getRandomValue(30, 90),  // Simulate deficient nitrogen
      p: this.getRandomValue(120, 180), // Simulate sufficient phosphorus
      k: this.getRandomValue(20, 60),  // Simulate deficient potassium
    };
    return of(readings).pipe(delay(this.SIMULATED_DELAY));
  }

  getPhReading(): Observable<{ph: number}> {
      const phReading = {
          ph: parseFloat(this.getRandomValue(6.5, 7.2).toFixed(1))
      };
      return of(phReading).pipe(delay(200));
  }

  // Original mock method remains for potential other uses
  getTankReadings(): Observable<TankReadings> {
    const readings: TankReadings = {
      methane: parseFloat(this.getRandomValue(3, 8).toFixed(2)),
      temp: parseFloat(this.getRandomValue(25, 35).toFixed(1)),
      humidity: parseFloat(this.getRandomValue(60, 85).toFixed(1)),
      ph: parseFloat(this.getRandomValue(6.5, 7.2).toFixed(1)),
      moisture: parseFloat(this.getRandomValue(50, 75).toFixed(1)),
    };
    return of(readings).pipe(delay(this.SIMULATED_DELAY));
  }

  private getRandomValue(min: number, max: number): number {
    return Math.random() * (max - min) + min;
  }
}

import { Injectable } from '@angular/core';
import { AnalysisResult } from './gemini.service';

export interface GalleryItem {
  id: number;
  date: string;
  imageBase64: string;
  analysisResult: AnalysisResult;
  thumbnailBase64: string;
}

@Injectable({ providedIn: 'root' })
export class GalleryService {
  private readonly STORAGE_KEY = 'plant_analysis_gallery';

  getGalleryItems(): GalleryItem[] {
    const itemsJson = localStorage.getItem(this.STORAGE_KEY);

    if (!itemsJson) {
      return [];
    }

    // Fix: Trim whitespace before checking for invalid strings.
    // " undefined " (with spaces) would bypass a strict check but crash JSON.parse
    const trimmedJson = itemsJson.trim();

    if (trimmedJson === 'undefined' || trimmedJson === 'null' || trimmedJson === '') {
      return [];
    }

    try {
      return JSON.parse(trimmedJson);
    } catch (e) {
      console.error('Error parsing gallery items from localStorage:', e);
      // If data is corrupt, clear it to recover the app
      localStorage.removeItem(this.STORAGE_KEY);
      return [];
    }
  }

  async addGalleryItem(imageBase64: string, analysisResult: AnalysisResult): Promise<void> {
    try {
      const thumbnailBase64 = await this.createThumbnail(imageBase64);
      const newItem: GalleryItem = {
        id: Date.now(),
        date: new Date().toISOString(),
        imageBase64,
        analysisResult,
        thumbnailBase64
      };

      const items = this.getGalleryItems();
      items.unshift(newItem); // Add to the beginning for chronological order
      localStorage.setItem(this.STORAGE_KEY, JSON.stringify(items));
    } catch (error) {
      console.error("Failed to add gallery item", error);
    }
  }

  deleteGalleryItem(id: number): void {
    let items = this.getGalleryItems();
    items = items.filter(item => item.id !== id);
    localStorage.setItem(this.STORAGE_KEY, JSON.stringify(items));
  }

  private createThumbnail(imageBase64: string, maxWidth = 150, maxHeight = 150): Promise<string> {
    return new Promise((resolve) => {
      const img = new Image();
      img.src = `data:image/jpeg;base64,${imageBase64}`;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        if (width > height) {
          if (width > maxWidth) {
            height *= maxWidth / width;
            width = maxWidth;
          }
        } else {
          if (height > maxHeight) {
            width *= maxHeight / height;
            height = maxHeight;
          }
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.drawImage(img, 0, 0, width, height);
          resolve(canvas.toDataURL('image/jpeg').split(',')[1]);
        } else {
          resolve(imageBase64); // Fallback if context fails
        }
      };
      img.onerror = () => {
        // Fallback to original if something goes wrong
        resolve(imageBase64);
      };
    });
  }
}

import { Component, ChangeDetectionStrategy, signal, inject, ViewChild, ElementRef, OnDestroy, output, computed, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { GeminiService, AnalysisResult } from '../../services/gemini.service';
import { Deficiency } from '../../models';
import { GalleryService, GalleryItem } from '../../services/gallery.service';
import { ImageGalleryComponent } from '../image-gallery/image-gallery.component';

type View = 'idle' | 'camera' | 'preview' | 'analyzing' | 'result' | 'error' | 'gallery';

@Component({
  selector: 'app-plant-analyser',
  templateUrl: './plant-analyser.component.html',
  styleUrls: ['./plant-analyser.component.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [CommonModule, ImageGalleryComponent]
})
export class PlantAnalyserComponent implements OnDestroy, OnInit {
  @ViewChild('videoElement') videoElement!: ElementRef<HTMLVideoElement>;
  @ViewChild('canvasElement') canvasElement!: ElementRef<HTMLCanvasElement>;

  generateFertilizer = output<Deficiency[]>();

  private geminiService = inject(GeminiService);
  private galleryService = inject(GalleryService);
  private stream: MediaStream | null = null;

  view = signal<View>('idle');
  imageBase64 = signal<string | null>(null);
  analysisResult = signal<AnalysisResult | null>(null);
  errorMessage = signal<string | null>(null);
  cameraError = signal<string | null>(null);
  galleryItems = signal<GalleryItem[]>([]);

  hasNpkDeficiency = computed(() => {
    const result = this.analysisResult();
    if (!result || !result.nutrientDeficiencies) return false;

    const lowerCaseNutrients = result.nutrientDeficiencies.map(d => d.nutrient.toLowerCase());
    return lowerCaseNutrients.includes('nitrogen') ||
           lowerCaseNutrients.includes('phosphorus') ||
           lowerCaseNutrients.includes('potassium');
  });

  ngOnInit(): void {
    this.refreshGallery();
  }

  ngOnDestroy(): void {
    this.stopCamera();
  }

  triggerFileInput(fileInput: HTMLInputElement): void {
    fileInput.click();
  }

  async startCamera(): Promise<void> {
    this.resetStateForNewImage();
    if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
        try {
            this.stream = await navigator.mediaDevices.getUserMedia({
                video: { facingMode: 'environment' } // Prefer rear camera
            });
            // We need a slight delay or check to ensure videoElement is available in DOM 
            // because view switching happens via Angular change detection
            this.view.set('camera');
            setTimeout(() => {
              if (this.videoElement) {
                this.videoElement.nativeElement.srcObject = this.stream;
              }
            }, 100);
        } catch (err: any) {
            console.error("Error accessing camera: ", err);
            this.cameraError.set("Could not access the camera. Please ensure you have granted permission and are using a secure (HTTPS) connection.");
        }
    } else {
        this.cameraError.set("Camera access is not supported by your browser.");
    }
  }

  stopCamera(): void {
    if (this.stream) {
      this.stream.getTracks().forEach(track => track.stop());
    }
    this.stream = null;
    if (this.videoElement && this.videoElement.nativeElement) {
       this.videoElement.nativeElement.srcObject = null;
    }
    if(this.view() === 'camera') {
        this.view.set('idle');
    }
  }

  capturePhoto(): void {
    if (this.view() !== 'camera') return;

    const video = this.videoElement.nativeElement;
    const canvas = this.canvasElement.nativeElement;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const context = canvas.getContext('2d');
    context?.drawImage(video, 0, 0, canvas.width, canvas.height);

    const dataUrl = canvas.toDataURL('image/jpeg');
    const base64String = dataUrl.split(',')[1];

    this.imageBase64.set(base64String);
    this.stopCamera();
    this.view.set('preview');
  }

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files[0]) {
      this.resetStateForNewImage();
      const file = input.files[0];
      const reader = new FileReader();
      reader.onload = (e) => {
        const base64String = (e.target?.result as string).split(',')[1];
        this.imageBase64.set(base64String);
        this.view.set('preview');
      };
      reader.readAsDataURL(file);
    }
  }

  async analyzeImage(): Promise<void> {
    const currentImage = this.imageBase64();
    if (!currentImage) return;

    this.view.set('analyzing');
    this.errorMessage.set(null);

    try {
      const result = await this.geminiService.analyzePlantImage(currentImage);
      this.analysisResult.set(result);
      await this.galleryService.addGalleryItem(currentImage, result);
      this.refreshGallery();
      this.view.set('result');
    } catch (error: any) {
      this.errorMessage.set(error.message || 'An unknown error occurred.');
      this.view.set('error');
    }
  }

  reset(): void {
    this.stopCamera();
    this.view.set('idle');
    this.imageBase64.set(null);
    this.analysisResult.set(null);
    this.errorMessage.set(null);
    this.cameraError.set(null);
    this.refreshGallery();
  }

  showGallery(): void {
    this.refreshGallery();
    this.view.set('gallery');
  }

  handleViewFromGallery(item: GalleryItem): void {
    this.imageBase64.set(item.imageBase64);
    this.analysisResult.set(item.analysisResult);
    this.view.set('result');
  }

  handleReanalyzeFromGallery(item: GalleryItem): void {
    this.imageBase64.set(item.imageBase64);
    this.analysisResult.set(null);
    this.analyzeImage();
  }

  handleDeleteFromGallery(id: number): void {
    this.galleryService.deleteGalleryItem(id);
    this.refreshGallery();
  }

  onGenerateFertilizer(): void {
    const result = this.analysisResult();
    if (!result) return;

    const npkMapping: { [key: string]: 'N' | 'P' | 'K' } = {
      'nitrogen': 'N',
      'phosphorus': 'P',
      'potassium': 'K'
    };

    const deficiencies: Deficiency[] = result.nutrientDeficiencies
      .map(def => {
        const key = def.nutrient.toLowerCase();
        if (npkMapping[key]) {
          return {
            nutrient: npkMapping[key],
            level: 'Deficient', // Assign a default level from analysis
            weight: 1           // Assign a default weight
          };
        }
        return null;
      })
      .filter((d): d is Deficiency => d !== null);

    if (deficiencies.length > 0) {
      this.generateFertilizer.emit(deficiencies);
    }
  }

  private resetStateForNewImage(): void {
    this.analysisResult.set(null);
    this.errorMessage.set(null);
    this.cameraError.set(null);
    this.imageBase64.set(null);
  }

  private refreshGallery(): void {
    this.galleryItems.set(this.galleryService.getGalleryItems());
  }
}

