#include <Wire.h>
#include <LiquidCrystal_I2C.h>
#include <SoftwareSerial.h>

/* -------- GPIO DEFINITIONS -------- */
#define RELAY_PIN 16      // D0
#define LCD_SDA   4       // D2
#define LCD_SCL   5       // D1
#define GSM_RX    14      // D5 (GSM TX)
#define GSM_TX    12      // D6 (GSM RX)

/* -------- OBJECTS -------- */
LiquidCrystal_I2C lcd(0x27, 16, 2);   // Change address if needed
SoftwareSerial gsm(GSM_RX, GSM_TX);   // RX, TX

String command = "";

/* -------- SETUP -------- */
void setup() {
  pinMode(RELAY_PIN, OUTPUT);
  digitalWrite(RELAY_PIN, LOW);

  Serial.begin(9600);      // Laptop App
  gsm.begin(9600);         // GSM Module

  Wire.begin(LCD_SDA, LCD_SCL);

  lcd.init();
  lcd.backlight();
  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print(F("System Ready"));

  delay(2000);
  Serial.println(F("ESP8266 Ready"));
}

/* -------- LOOP -------- */
void loop() {

  // Read command from Laptop App
  if (Serial.available()) {
    command = Serial.readStringUntil('\n');
    command.trim();

    if (command == "DETECTED") {
      humanDetected();
    }
    else if (command == "CLEAR") {
      clearAlert();
    }
  }

  // Forward GSM responses to Serial Monitor
  if (gsm.available()) {
    Serial.write(gsm.read());
  }
}

/* -------- FUNCTIONS -------- */

void humanDetected() {
  digitalWrite(RELAY_PIN, HIGH);   // Buzzer ON

  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print(F("HUMAN DETECTED"));

  Serial.println(F("Human Detected"));
  getLocation();
}

void clearAlert() {
  digitalWrite(RELAY_PIN, LOW);    // Buzzer OFF

  lcd.clear();
  lcd.setCursor(0, 0);
  lcd.print(F("No Human"));

  Serial.println(F("System Cleared"));
}

void getLocation() {
  Serial.println(F("Fetching Location"));

  gsm.println(F("AT"));
  delay(1000);

  gsm.println(F("AT+CGATT=1"));
  delay(1000);

  gsm.println(F("AT+CIPGSMLOC=1,1"));   // GSM-based location
  delay(3000);
}
