  ];

  readonly organicBaseProfile = { "N": 1, "P": 1, "K": 1, "Ca": 1, "S": 1, "Mg": 1 };

  // --- Context State ---
  selectedCrop = signal<Crop | null>(null);

  constructor() {
    this.startTankMonitoring();

    // Listen for physical device disconnection
    if (typeof navigator !== 'undefined' && 'serial' in navigator) {
      (navigator as any).serial.addEventListener('disconnect', (event: any) => {
        if (event.target === this.port) {
           console.log('Device disconnected physically.');
           this.handleDisconnect();
        }
      });
    }
  }

  // --- Actions ---

  // Connect via Web Serial for NPK (replaces mock logic)
  async connectToDevice(): Promise<boolean> {
    await this.connectSerial();
    return this.isSerialConnected();
  }

  // Read NPK: Uses Serial if connected, otherwise uses mock
  async readNPK(): Promise<void> {
    if (this.isSerialConnected() && this.writer) {
      // Send Request Command to ESP32
      try {
        await this.writer.write('READ_NPK\n');
        console.log('Sent READ_NPK command');
      } catch (e) {
        console.error('Failed to send NPK read command', e);
      }
    } else {
      // Fallback: Simulated Data
      return new Promise((resolve) => {
        setTimeout(() => {
          this.npkReadings.set({
            n: Math.floor(Math.random() * (200 - 20) + 20),
            p: Math.floor(Math.random() * (100 - 10) + 10),
            k: Math.floor(Math.random() * (300 - 50) + 50),
            timestamp: new Date()
          });
          resolve();
        }, 800);
      });
    }
  }

  // --- Web Serial for Tank Monitor & Motor Control ---
  async connectSerial() {
    if (!('serial' in navigator)) {
      alert('Web Serial API not supported. Please use Chrome or Edge.');
      return;
    }

    if (this.isSerialConnected()) return;

    try {
      this.port = await (navigator as any).serial.requestPort();
      await this.port.open({ baudRate: 9600 });

      this.isSerialConnected.set(true);
      this.isConnected.set(true); // Update general connection status

      // Setup Writer for sending commands to Arduino
      const textEncoder = new TextEncoderStream();
      textEncoder.readable.pipeTo(this.port.writable);
      this.writer = textEncoder.writable.getWriter();

      // Start Reading loop
      this.readSerialLoop(this.port);
    } catch (error: any) {
      if (error.name === 'NotFoundError' || error.toString().includes('No port selected')) {
        console.warn('User cancelled port selection.');
        return;
      }
      console.error('Serial Connection Error:', error);
      this.handleDisconnect();
    }
  }

  // Set Motor Direction ('F' or 'B')
  async setDirection(id: 2 | 3, dir: 'F' | 'B') {
    if (id === 2) this.grinderDirection.set(dir);
    if (id === 3) this.agitatorDirection.set(dir);

    // If currently running, update the motor immediately
    const isRunning = id === 2 ? this.relay2State() : this.relay3State();

    if (isRunning && this.writer && this.isSerialConnected()) {
       // Get Correct Speed
       const speed = id === 2 ? this.grinderSpeed() : this.agitatorSpeed();
       const motorChar = id === 2 ? 'A' : 'B';
       const safeSpeed = Math.floor(speed);

       const command = `MOTOR:${motorChar}:${dir}:${safeSpeed}\n`;
       console.log('Updating Direction:', command.trim());

       try {
         await this.writer.write(command);
       } catch (err: any) {
         if (err.toString().includes('The device has been lost')) {
            console.warn('Device lost during direction update.');
         } else {
            console.error('Failed to set direction:', err);
         }
         this.handleDisconnect();
       }
    }
  }

  // Toggle Relay or Motor State based on Arduino Protocol
  async toggleRelay(id: 1 | 2 | 3, state: boolean) {
    // UI Update immediately for responsiveness (Optimistic)
    if (id === 1) this.relay1State.set(state);
    if (id === 2) this.relay2State.set(state);
    if (id === 3) this.relay3State.set(state);

    if (!this.writer || !this.isSerialConnected()) return;

    try {
      let command = '';
      if (id === 1) {
        // Heater (Pin 4 Relay): "RELAY:1" (ON) or "RELAY:0" (OFF)
        command = `RELAY:${state ? 1 : 0}\n`;
      } 
      else if (id === 2) {
        // Grinder (Motor A): "MOTOR:A:F:speed" (ON) or "MOTOR:A:S:0" (OFF)
        const speed = Math.floor(this.grinderSpeed());
        const dir = this.grinderDirection();
        // If turning ON, use current direction (F/B). If OFF, use 'S'.
        const mode = state ? dir : 'S'; 
        command = `MOTOR:A:${mode}:${state ? speed : 0}\n`;
      } 
      else if (id === 3) {
        // Agitator (Motor B): "MOTOR:B:F:speed" (ON) or "MOTOR:B:S:0" (OFF)
        const speed = Math.floor(this.agitatorSpeed());
        const dir = this.agitatorDirection();
        const mode = state ? dir : 'S';
        command = `MOTOR:B:${mode}:${state ? speed : 0}\n`;
      }

      console.log('Sending Serial Command:', command.trim());
      await this.writer.write(command);

    } catch (err: any) {
      if (err.toString().includes('The device has been lost')) {
         console.warn('Device lost during relay toggle.');
      } else {
         console.error('Failed to write to serial:', err);
      }
      this.handleDisconnect();
    }
  }

  // Set Motor Speed dynamically (Only affects if motor is running)
  async setMotorSpeed(id: 2 | 3, speed: number) {
    const safeSpeed = Math.floor(speed);

    // Update local state signal
    if (id === 2) this.grinderSpeed.set(safeSpeed);
    if (id === 3) this.agitatorSpeed.set(safeSpeed);

    // If disconnected or motor is currently OFF, don't send command yet
    const isRunning = id === 2 ? this.relay2State() : this.relay3State();
    if (!this.writer || !this.isSerialConnected() || !isRunning) {
       return;
    }

    try {
      const motorChar = id === 2 ? 'A' : 'B';
      // Use current direction instead of hardcoded 'F'
      const dir = id === 2 ? this.grinderDirection() : this.agitatorDirection();
      const command = `MOTOR:${motorChar}:${dir}:${safeSpeed}\n`;

      console.log('Updating Speed:', command.trim());
      await this.writer.write(command);
    } catch (err: any) {
       if (err.toString().includes('The device has been lost')) {
          console.warn('Device lost during speed update.');
       } else {
          console.error('Failed to set motor speed:', err);
       }
       this.handleDisconnect();
    }
  }

  private async readSerialLoop(port: any) {
    const textDecoder = new TextDecoderStream();
    const readableStreamClosed = port.readable.pipeTo(textDecoder.writable);
    const reader = textDecoder.readable.getReader();

    let buffer = '';

    try {
      while (true) {
        const { value, done } = await reader.read();
        if (done) break;
        if (value) {
          buffer += value;
          const lines = buffer.split('\n');
          for (let i = 0; i < lines.length - 1; i++) {
             this.parseSerialData(lines[i]);
          }
          buffer = lines[lines.length - 1];
        }
      }
    } catch (error) {
      console.error('Serial Read Error:', error);
    } finally {
      try {
        reader.releaseLock();
      } catch (e) {
        // Ignore lock release errors on closed ports
      }
      this.handleDisconnect();
    }
  }

  private async handleDisconnect() {
    // Only cleanup if we think we are connected
    if (!this.isSerialConnected()) return;

    console.log('Cleaning up connection...');
    this.isSerialConnected.set(false);
    this.isConnected.set(false);

    // Attempt to close writer
    if (this.writer) {
      try {
         // releaseLock is usually sufficient if the stream is broken
         await this.writer.releaseLock(); 
      } catch (e) {
         console.debug('Writer cleanup issue:', e);
      }
      this.writer = null;
    }

    // Port cleaning is handled by the browser mostly, 
    // but good to nullify reference.
    this.port = null;

    // Reset UI State
    this.relay1State.set(false);
    this.relay2State.set(false);
    this.relay3State.set(false);
  }

  private parseSerialData(line: string) {
    const text = line.trim();
    if (!text) return;

    // Debug output to see what ESP32 is sending
    console.log('ESP32 Serial RX:', text);

    // 1. Try JSON Parsing (Strict)
    // Expected JSON: {"t":25.0,"h":60.0,"g":300,"a":0, "n": 40, "p": 30, "k": 50}
    if (text.startsWith('{') && text.endsWith('}')) {
      try {
        const data = JSON.parse(text);

        // --- NPK Sensor Data ---
        if (data.n !== undefined && data.p !== undefined && data.k !== undefined) {
           this.npkReadings.set({
             n: Number(data.n),
             p: Number(data.p),
             k: Number(data.k),
             timestamp: new Date()
           });
        }

        // --- Tank Sensor Data ---
        this.tankReadings.update(current => ({
          ...current,
          temperature: typeof data.t === 'number' ? data.t : current.temperature,
          humidity: typeof data.h === 'number' ? data.h : current.humidity,
          methane: typeof data.g === 'number' ? data.g : current.methane,
          // 'a' (alarm) could be used to trigger UI warnings in future
        }));
        return; // Success
      } catch (e) {
        console.debug('JSON parse failed, trying regex fallback');
      }
    }

    // 2. Try CSV (comma separated values: "10,20,30" for N,P,K)
    const csvMatch = text.match(/^(\d+)\s*,\s*(\d+)\s*,\s*(\d+)$/);
    if (csvMatch) {
       this.npkReadings.set({
         n: parseInt(csvMatch[1], 10),
         p: parseInt(csvMatch[2], 10),
         k: parseInt(csvMatch[3], 10),
         timestamp: new Date()
       });
       console.log('Parsed CSV NPK');
       return;
    }

    // 3. Try Multi-line Accumulation Regex (case insensitive)
    // Supports: "N: 10", "Nitrogen = 20", "P: 30", etc.
    let updated = false;

    // Match N
    const nMatch = text.match(/(?:N|Nitrogen)[:=\s]*(\d+)/i);
    if (nMatch) {
        this.partialNpk.n = parseInt(nMatch[1], 10);
        updated = true;
    }

    // Match P
    const pMatch = text.match(/(?:P|Phosphorus)[:=\s]*(\d+)/i);
    if (pMatch) {
        this.partialNpk.p = parseInt(pMatch[1], 10);
        updated = true;
    }

    // Match K
    const kMatch = text.match(/(?:K|Potassium)[:=\s]*(\d+)/i);
    if (kMatch) {
        this.partialNpk.k = parseInt(kMatch[1], 10);
        updated = true;
    }

    // Check if partial buffer is complete
    if (this.partialNpk.n !== null && this.partialNpk.p !== null && this.partialNpk.k !== null) {
        this.npkReadings.set({
            n: this.partialNpk.n,
            p: this.partialNpk.p,
            k: this.partialNpk.k,
            timestamp: new Date()
        });
        console.log('NPK Readings Updated via Partial Accumulation', this.partialNpk);
        // Reset buffer
        this.partialNpk = { n: null, p: null, k: null };
    }
  }

  private startTankMonitoring() {
    // Only run simulation if NOT connected to Serial
    setInterval(() => {
      if (this.isSerialConnected()) return; 

      const newPh = parseFloat((Math.random() * (8.5 - 5.5) + 5.5).toFixed(2));

      if (this.isConnected()) {
        // Full simulation mode (Mock Connected)
        this.tankReadings.set({
          methane: parseFloat((Math.random() * (500 - 100) + 100).toFixed(1)),
          temperature: parseFloat((Math.random() * (35 - 25) + 25).toFixed(1)),
          humidity: parseFloat((Math.random() * (90 - 40) + 40).toFixed(1)),
          ph: newPh
        });
      }
    }, 3000);
  }
}

